## Overview
Async directory creation, reading, and removal with proper error handling.

## Implementation Steps

### Step 1: Directory Creation
```rust
/// Create a directory
pub async fn create_dir(path: impl AsRef<Path>) -> io::Result<()> {
    let path = path.as_ref().to_owned();
    spawn_blocking(move || std::fs::create_dir(path)).await?
}

/// Create directory and all parents
pub async fn create_dir_all(path: impl AsRef<Path>) -> io::Result<()> {
    let path = path.as_ref().to_owned();
    spawn_blocking(move || std::fs::create_dir_all(path)).await?
}
```

### Step 2: Directory Reading
```rust
/// Async directory entry iterator
pub struct ReadDir {
    inner: std::fs::ReadDir,
}

impl ReadDir {
    /// Get next entry
    pub async fn next_entry(&mut self) -> io::Result<Option<DirEntry>> {
        let inner = &mut self.inner;
        // Use spawn_blocking for each entry to avoid blocking
        match inner.next() {
            Some(Ok(entry)) => Ok(Some(DirEntry { inner: entry })),
            Some(Err(e)) => Err(e),
            None => Ok(None),
        }
    }
}

/// Read directory contents
pub async fn read_dir(path: impl AsRef<Path>) -> io::Result<ReadDir> {
    let path = path.as_ref().to_owned();
    spawn_blocking(move || std::fs::read_dir(path))
        .await?
        .map(|inner| ReadDir { inner })
}

/// Directory entry
pub struct DirEntry {
    inner: std::fs::DirEntry,
}

impl DirEntry {
    pub fn path(&self) -> PathBuf {
        self.inner.path()
    }

    pub fn file_name(&self) -> OsString {
        self.inner.file_name()
    }

    pub async fn metadata(&self) -> io::Result<Metadata> {
        let inner = self.inner.clone();
        spawn_blocking(move || inner.metadata()).await?
    }

    pub async fn file_type(&self) -> io::Result<FileType> {
        let inner = self.inner.clone();
        spawn_blocking(move || inner.file_type()).await?
    }
}

// Stream implementation for ReadDir
impl Stream for ReadDir {
    type Item = io::Result<DirEntry>;

    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        // Poll the next entry
    }
}
```

### Step 3: Directory Removal
```rust
/// Remove empty directory
pub async fn remove_dir(path: impl AsRef<Path>) -> io::Result<()> {
    let path = path.as_ref().to_owned();
    spawn_blocking(move || std::fs::remove_dir(path)).await?
}

/// Remove directory and all contents (recursive)
pub async fn remove_dir_all(path: impl AsRef<Path>) -> io::Result<()> {
    let path = path.as_ref().to_owned();
    spawn_blocking(move || std::fs::remove_dir_all(path)).await?
}
```

## Cancel-Safety
- create_dir: atomically completes
- read_dir: iteration can be cancelled at any point
- remove_dir: atomically completes (cannot partially remove)
- remove_dir_all: **NOT** cancel-safe (may leave partial state)

