fn e2e_directory_tree_operations() {
    setup_test_logging();

    let rt = LabRuntime::new();
    rt.block_on(async {
        info\!("Starting directory operations E2E test");

        let temp = tempdir().unwrap();
        let base = temp.path().join("project");

        // Create project structure
        info\!(path = ?base, "Creating project structure");
        create_dir_all(base.join("src/modules")).await.unwrap();
        create_dir_all(base.join("tests/fixtures")).await.unwrap();
        create_dir(base.join("docs")).await.unwrap();
        info\!("Directory structure created");

        // Create some files
        File::create(base.join("src/main.rs")).await.unwrap();
        File::create(base.join("src/modules/mod.rs")).await.unwrap();
        File::create(base.join("tests/test_main.rs")).await.unwrap();
        info\!("Files created");

        // Enumerate structure
        info\!("Enumerating directory tree");
        let mut count = 0;
        async fn count_entries(path: &Path) -> io::Result<usize> {
            let mut count = 0;
            let mut entries = read_dir(path).await?;
            while let Some(entry) = entries.next_entry().await? {
                count += 1;
                if entry.file_type().await?.is_dir() {
                    count += Box::pin(count_entries(&entry.path())).await?;
                }
            }
            Ok(count)
        }
        count = count_entries(&base).await.unwrap();
        info\!(total_entries = count, "Enumeration complete");
        assert\!(count >= 7); // At least our created items

        // Cleanup
        info\!("Removing directory tree");
        remove_dir_all(&base).await.unwrap();
        assert\!(\!base.exists());
        info\!("E2E test completed successfully");
    });
}
